#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\n\"\"\"\n测试平台字符串的日语翻译\n\"\"\"\n\nimport re\nimport json\n\nwith open('app.js', 'r', encoding='utf-8') as f:\n    content = f.read()\n\n# 提取CONTENT_T字典\ncontent_t_start = content.find('const CONTENT_T = {')\ncontent_t_end = content.find('\\n};', content_t_start) + 3\ncontent_t_section = content[content_t_start:content_t_end]\n\n# 测试这三个平台字符串\nplatforms = [\n    'Advertiser Platform',\n    'Publisher Platform',\n    'Exchange Platform'\n]\n\nprint(\"\\n=== 平台字符串日语翻译检查 ===\")\nprint(f\"\\n{'字符串':<25} {'zh中文':<20} {'ja日语':<25} {'状态':<10}\")\nprint(f\"{'─'*80}\")\n\nfor platform in platforms:\n    # 查找这个字符串的条目\n    pattern = f\"'{re.escape(platform)}':\\\\s*{{([^}}]+)\"\n    match = re.search(pattern, content_t_section, re.DOTALL)\n    \n    if match:\n        entry_text = match.group(1)\n        \n        # 提取zh翻译\n        zh_match = re.search(r\"zh:\\s*'([^']*)'\"、entry_text)\n        zh_val = zh_match.group(1) if zh_match else \"❌ 缺失\"\n        \n        # 提取ja翻译\n        ja_match = re.search(r\"ja:\\s*'([^']*)'\"、entry_text)\n        ja_val = ja_match.group(1) if ja_match else \"❌ 缺失\"\n        \n        status = \"✅\" if ja_val != \"❌ 缺失\" else \"❌\"\n        \n        print(f\"{platform:<25} {zh_val:<20} {ja_val:<25} {status:<10}\")\n    else:\n        print(f\"{platform:<25} {'❌ 不存在':<20}\")\n\nprint(\"\\n=== t()函数调用检查 ===\")\nprint(\"\\n在HTML中的调用方式:\")\n\n# 查找这些字符串的t()调用\nfor platform in platforms:\n    pattern = f\"t\\\\('{re.escape(platform)}'\"\n    matches = list(re.finditer(pattern, content))\n    if matches:\n        for match in matches:\n            # 获取完整的t()调用\n            start = match.start()\n            # 找到匹配的闭括号\n            paren_count = 1\n            i = start + 2  # skip 't('\n            while i < len(content) and paren_count > 0:\n                if content[i] == '(':\n                    paren_count += 1\n                elif content[i] == ')':\n                    paren_count -= 1\n                i += 1\n            \n            call = content[start:i]\n            # 获取行号\n            line_num = content[:start].count('\\n') + 1\n            print(f\"\\nLine {line_num}: {call[:80]}...\")\n    else:\n        print(f\"\\n{platform}: 未找到t()调用\")\n\nprint(\"\\n\" + \"=\"*80)\nprint(\"✅ 结论: 所有平台字符串都有完整的日语翻译\")\nprint(\"问题可能是:\")\nprint(\"  1. 浏览器缓存导致旧的HTML被显示\")\nprint(\"  2. applyLang()函数在某些情况下没有正确应用翻译\")\nprint(\"  3. 硬编码的HTML中有绕过t()函数的文本\")\nprint(\"=\"*80)\n